package github.chains;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.transform.OutputKeys;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.io.File;

public class Main {
    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <path-to-pom.xml>");
            System.exit(1);
        }

        File pomFile = new File(args[0]);
        if (!pomFile.exists()) {
            System.err.println("File not found: " + pomFile.getAbsolutePath());
            System.exit(1);
        }

        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(pomFile);
        doc.getDocumentElement().normalize();

        boolean modified = false;

        NodeList compilerPlugins = doc.getElementsByTagName("artifactId");
        for (int i = 0; i < compilerPlugins.getLength(); i++) {
            Element artifactId = (Element) compilerPlugins.item(i);
            if ("maven-compiler-plugin".equals(artifactId.getTextContent().trim())) {
                Element plugin = (Element) artifactId.getParentNode();
                NodeList configList = plugin.getElementsByTagName("configuration");
                if (configList.getLength() > 0) {
                    Element config = (Element) configList.item(0);
                    modified |= updateVersionElement(config, "source", "1.7");
                    modified |= updateVersionElement(config, "target", "1.7");
                }
            }
        }

        if (modified) {
            TransformerFactory transformerFactory = TransformerFactory.newInstance();
            Transformer transformer = transformerFactory.newTransformer();
            transformer.setOutputProperty(OutputKeys.INDENT, "yes");
            transformer.setOutputProperty(OutputKeys.STANDALONE, "yes");
            transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "4");

            DOMSource source = new DOMSource(doc);
            StreamResult result = new StreamResult(pomFile);
            transformer.transform(source, result);

            System.out.println("Successfully updated pom.xml: source/target changed to 1.7");
        } else {
            System.out.println("No changes needed in pom.xml");
        }
    }

    private static boolean updateVersionElement(Element parent, String tagName, String newValue) {
        NodeList nodes = parent.getElementsByTagName(tagName);
        if (nodes.getLength() > 0) {
            Element element = (Element) nodes.item(0);
            String currentValue = element.getTextContent().trim();
            if (!newValue.equals(currentValue)) {
                element.setTextContent(newValue);
                System.out.println("Updated " + tagName + " from " + currentValue + " to " + newValue);
                return true;
            }
        }
        return false;
    }
}

