package github.chains;

import com.github.javaparser.ParseResult;
import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.body.ClassOrInterfaceDeclaration;
import com.github.javaparser.ast.body.ConstructorDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.expr.VariableDeclarationExpr;
import com.github.javaparser.ast.stmt.BlockStmt;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.type.ClassOrInterfaceType;

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <path-to-java-file>");
            System.exit(1);
        }

        String filePath = args[0];
        File file = new File(filePath);
        if (!file.exists()) {
            System.err.println("File not found: " + file.getAbsolutePath());
            System.exit(1);
        }

        String content = new String(Files.readAllBytes(Paths.get(filePath)));
        ParseResult<CompilationUnit> result = StaticJavaParser.parse(content);

        if (!result.isSuccessful() || result.getResult().isEmpty()) {
            System.err.println("Failed to parse: " + result.getProblems());
            System.exit(1);
        }

        CompilationUnit cu = result.getResult().get();
        boolean modified = false;

        if (filePath.contains("JettyStubHttpServer.java")) {
            modified = transformJettyStubHttpServer(cu);
        } else if (filePath.contains("JadlerHandler.java")) {
            modified = transformJadlerHandler(cu);
        }

        if (modified) {
            try (FileWriter writer = new FileWriter(file)) {
                writer.write(cu.toString());
            }
            System.out.println("Successfully transformed: " + filePath);
        } else {
            System.out.println("No changes needed: " + filePath);
        }
    }

    private static boolean transformJettyStubHttpServer(CompilationUnit cu) {
        boolean modified = false;

        for (ImportDeclaration imp : new NodeList<>(cu.getImports().toArray(new ImportDeclaration[0]))) {
            if (imp.getNameAsString().equals("org.eclipse.jetty.server.nio.SelectChannelConnector")) {
                imp.remove();
                modified = true;
            }
        }

        cu.addImport("org.eclipse.jetty.server.ServerConnector");
        cu.addImport("org.eclipse.jetty.server.HttpConfiguration");
        cu.addImport("org.eclipse.jetty.server.HttpConnectionFactory");
        modified = true;

        for (ClassOrInterfaceDeclaration cls : cu.findAll(ClassOrInterfaceDeclaration.class)) {
            if (cls.getNameAsString().equals("JettyStubHttpServer")) {
                for (ConstructorDeclaration ctor : cls.getConstructors()) {
                    BlockStmt body = ctor.getBody();
                    NodeList<com.github.javaparser.ast.body.Parameter> params = ctor.getParameters();

                    if (params.size() == 1 && params.get(0).getNameAsString().equals("port")) {
                        body.getStatements().removeIf(stmt -> {
                            if (stmt instanceof ExpressionStmt) {
                                ExpressionStmt exprStmt = (ExpressionStmt) stmt;
                                if (exprStmt.getExpression() instanceof MethodCallExpr) {
                                    MethodCallExpr method = (MethodCallExpr) exprStmt.getExpression();
                                    if (method.getNameAsString().equals("setSendServerVersion") ||
                                        method.getNameAsString().equals("setSendDateHeader")) {
                                        return true;
                                    }
                                }
                            }
                            return false;
                        });

                        body.getStatements().removeIf(stmt -> {
                            if (stmt instanceof ExpressionStmt) {
                                ExpressionStmt exprStmt = (ExpressionStmt) stmt;
                                if (exprStmt.getExpression() instanceof VariableDeclarationExpr) {
                                    VariableDeclarationExpr var = (VariableDeclarationExpr) exprStmt.getExpression();
                                    for (com.github.javaparser.ast.body.VariableDeclarator declarator : var.getVariables()) {
                                        if (declarator.getType().asString().contains("SelectChannelConnector")) {
                                            return true;
                                        }
                                    }
                                }
                            }
                            return false;
                        });

                        body.getStatements().removeIf(stmt -> {
                            if (stmt instanceof ExpressionStmt) {
                                ExpressionStmt exprStmt = (ExpressionStmt) stmt;
                                if (exprStmt.getExpression() instanceof MethodCallExpr) {
                                    MethodCallExpr method = (MethodCallExpr) exprStmt.getExpression();
                                    if (method.getNameAsString().equals("setPort")) {
                                        return true;
                                    }
                                }
                            }
                            return false;
                        });

                        int insertIndex = 0;
                        for (int i = 0; i < body.getStatements().size(); i++) {
                            if (body.getStatement(i).toString().contains("new Server()")) {
                                insertIndex = i + 1;
                                break;
                            }
                        }

                        String httpConfigCode = "HttpConfiguration httpConfig = new HttpConfiguration();\n" +
                                "        httpConfig.setSendServerVersion(false);\n" +
                                "        httpConfig.setSendDateHeader(false);";
                        body.addStatement(insertIndex, httpConfigCode);

                        String connectorCode = "this.httpConnector = new ServerConnector(server, new HttpConnectionFactory(httpConfig));";
                        body.addStatement(insertIndex + 1, connectorCode);

                        String portCode = "((ServerConnector) this.httpConnector).setPort(port);";
                        body.addStatement(insertIndex + 2, portCode);

                        modified = true;
                    }
                }

                for (MethodDeclaration method : cls.getMethods()) {
                    if (method.getNameAsString().equals("getPort")) {
                        method.getBody().ifPresent(body -> {
                            body.getStatements().clear();
                            body.addStatement("return server.getPort();");
                        });
                        modified = true;
                    }
                }
            }
        }

        return modified;
    }

    private static boolean transformJadlerHandler(CompilationUnit cu) {
        boolean modified = false;

        for (MethodDeclaration method : cu.findAll(MethodDeclaration.class)) {
            if (method.getNameAsString().equals("handle") && method.getParameters().size() == 4) {
                com.github.javaparser.ast.body.Parameter targetParam = method.getParameter(0);
                if (targetParam.getType().asString().equals("String")) {
                    targetParam.setType("java.lang.String");
                    targetParam.setName("target");

                    com.github.javaparser.ast.body.Parameter baseRequestParam = method.getParameter(1);
                    baseRequestParam.setType("org.eclipse.jetty.server.Request");
                    baseRequestParam.setName("baseRequest");

                    com.github.javaparser.ast.body.Parameter requestParam = method.getParameter(2);
                    requestParam.setType("javax.servlet.http.HttpServletRequest");
                    requestParam.setName("request");

                    com.github.javaparser.ast.body.Parameter responseParam = method.getParameter(3);
                    responseParam.setType("javax.servlet.http.HttpServletResponse");
                    responseParam.setName("response");

                    method.setAnnotationOverride(false);

                    NodeList<com.github.javaparser.ast.body.Parameter> newParams = new NodeList<>();
                    newParams.add(new com.github.javaparser.ast.body.Parameter(
                        new ClassOrInterfaceType(null, "java.lang.String"), "target"));
                    newParams.add(new com.github.javaparser.ast.body.Parameter(
                        new ClassOrInterfaceType(null, "org.eclipse.jetty.server.Request"), "baseRequest"));
                    newParams.add(new com.github.javaparser.ast.body.Parameter(
                        new ClassOrInterfaceType(null, "javax.servlet.http.HttpServletRequest"), "request"));
                    newParams.add(new com.github.javaparser.ast.body.Parameter(
                        new ClassOrInterfaceType(null, "javax.servlet.http.HttpServletResponse"), "response"));

                    method.setParameters(newParams);
                    modified = true;
                }
            }
        }

        return modified;
    }
}

